css:
.loader {
  width: fit-content;
  font-size: 34px;
  font-family: monospace;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #9333ea);
  background: linear-gradient(90deg,var(--loader-color, #9333ea),var(--loader-secondary-color, #f0abfc)) -1ch/1ch 100% no-repeat text;
  animation: l13 2s steps(8,jump-none) infinite;
}
.loader:before {
  content: "Loading";
}
@keyframes l13 {
  to {background-position: 100%}
}
